第三章 Web组件拦截器、servlet、Filter
拦截器拦截器是SpringMVC中的一种对象，能拦截对Controller的请求。拦截器框架中由系统的拦截器，可以自定义拦截器。实现对请求的预先处理。
SpringMVC实现自定义拦截器：

创建类实现SpringMVC框架的HandlerInterceptor接口public interface HandlerInterceptor &#123;    default boolean preHandle(HttpServletRequest request, HttpServletResponse response, Object handler) throws Exception &#123;        return true;    &#125;    default void postHandle(HttpServletRequest request, HttpServletResponse response, Object handler, @Nullable ModelAndView modelAndView) throws Exception &#123;    &#125;    default void afterCompletion(HttpServletRequest request, HttpServletResponse response, Object handler, @Nullable Exception ex) throws Exception &#123;    &#125;&#125;
需在SpringMVC的配置文件中，声明拦截器&lt;mvc:interceptors&gt;    &lt;mvc:interceptor&gt;        &lt;mvc:mapping path=&quot;url&quot;/&gt;        &lt;bean class=&quot;拦截器的全限定名称&quot;/&gt;    &lt;/mvc:interceptor&gt;&lt;/mvc:interceptors&gt;

SpringBoot实现拦截器：

自定义拦截器package com.example.web;import org.springframework.web.servlet.HandlerInterceptor;import javax.servlet.http.HttpServletRequest;import javax.servlet.http.HttpServletResponse;/** * 自定义的拦截器 */public class LoginInterceptor implements HandlerInterceptor &#123;    /**     * @param request     * @param response     * @param handler  被拦截的控制器对象     * @return boolean     * true：请求被Controller处理     * false：请求被拦截     */    @Override    public boolean preHandle(HttpServletRequest request, HttpServletResponse response, Object handler) throws Exception &#123;        //判断是否通过拦截器的代码        System.out.println(&quot;拦截器被执行&quot;);        return true;    &#125;&#125;
将拦截器对象注入容器package com.example.config;import com.example.web.LoginInterceptor;import org.springframework.context.annotation.Configuration;import org.springframework.web.servlet.HandlerInterceptor;import org.springframework.web.servlet.config.annotation.InterceptorRegistry;import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;@Configurationpublic class HandlerInterceptorConfig implements WebMvcConfigurer &#123;    //添加拦截器对象，注入到容器中    @Override    public void addInterceptors(InterceptorRegistry registry) &#123;        //创建拦截器对象        HandlerInterceptor interceptor = new LoginInterceptor();        //指定拦截的url请求        String path[] = &#123;&quot;/user/**&quot;&#125;;        //指定不拦截的地址        String excludePath[] = &#123;&quot;/user/login&quot;&#125;;        registry.addInterceptor(interceptor).addPathPatterns(path).excludePathPatterns(excludePath);    &#125;&#125;
写Controller类进行测试package com.example.controller;import org.springframework.stereotype.Controller;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.ResponseBody;@Controllerpublic class HandlerInterceptorController &#123;    @RequestMapping(&quot;/user/register&quot;)    @ResponseBody    public String userRegister()&#123;        return &quot;访问/user/register&quot;;    &#125;    @RequestMapping(&quot;/user/login&quot;)    @ResponseBody    public String userLogin()&#123;        return &quot;访问/user/login&quot;;    &#125;&#125;

Servlet在SpringBoot中使用Servlet对象使用步骤：

创建Servlet类。创建类继承HttpServlet。package com.example.web;import javax.servlet.ServletException;import javax.servlet.http.HttpServlet;import javax.servlet.http.HttpServletRequest;import javax.servlet.http.HttpServletResponse;import java.io.IOException;import java.io.PrintWriter;//创建Servlet类public class Servlet extends HttpServlet &#123;    @Override    protected void doGet(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException &#123;        doPost(req, resp);    &#125;    @Override    protected void doPost(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException &#123;        //使用HttpServletResponse输出数据，应答结果        resp.setContentType(&quot;text/html;charset=utf-8&quot;);        PrintWriter out = resp.getWriter();        out.println(&quot;执行servlet&quot;);        out.flush();        out.close();    &#125;&#125;
注册Servlet，让框架能找到Servlet。package com.example.config;import com.example.web.Servlet;import org.springframework.boot.web.servlet.ServletRegistrationBean;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;@Configurationpublic class ServletConfig &#123;    //定义方法，注册Servlet对象    @Bean    public ServletRegistrationBean servletRegistrationBean()&#123;        //public ServletRegistrationBean(T servlet, String... urlMappings)        //第一个参数是Servlet对象，第二个参数是url地址        //ServletRegistrationBean bean = new ServletRegistrationBean(new Servlet(),&quot;/servlet&quot;);        //无参构造，单独设置参数        ServletRegistrationBean bean = new ServletRegistrationBean();        bean.setServlet(new Servlet());        bean.addUrlMappings(&quot;/servlet_01&quot;,&quot;/servlet_02&quot;); // &lt;url-pattern&gt;        return bean;    &#125;&#125;

Filter过滤器Filter是Servlet规范中的过滤器，可以处理请求，对请求的参数、属性进行调整。常常在过滤器中处理字符编码使用步骤：

创建自定义的过滤器类package com.example.config;import com.example.web.MyFilter;import org.springframework.boot.web.servlet.FilterRegistrationBean;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;@Configurationpublic class FilterConfig &#123;    @Bean    public FilterRegistrationBean filterRegistration() &#123;        FilterRegistrationBean bean = new FilterRegistrationBean();        bean.setFilter(new MyFilter());        bean.addUrlPatterns(&quot;/user/*&quot;);        return bean;    &#125;&#125;
注册Filter过滤器对象package com.example.config;import com.example.web.MyFilter;import org.springframework.boot.web.servlet.FilterRegistrationBean;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;@Configurationpublic class FilterConfig &#123;    @Bean    public FilterRegistrationBean filterRegistration() &#123;        FilterRegistrationBean bean = new FilterRegistrationBean();        bean.setFilter(new MyFilter());        bean.addUrlPatterns(&quot;/user/*&quot;);        return bean;    &#125;&#125;
写Controller类进行测试package com.example.controller;import org.springframework.stereotype.Controller;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.ResponseBody;@Controllerpublic class HandlerInterceptorController &#123;    @RequestMapping(&quot;/user/register&quot;)    @ResponseBody    public String userRegister()&#123;        return &quot;访问/user/register&quot;;    &#125;    @RequestMapping(&quot;/user/login&quot;)    @ResponseBody    public String userLogin()&#123;        return &quot;访问/user/login&quot;;    &#125;    @RequestMapping(&quot;/query&quot;)    @ResponseBody    public String query()&#123;        return &quot;访问/query&quot;;    &#125;&#125;

字符集过滤器CharacterEncodingFilter：解决post请求中乱码的问题在SpringMVC框架，在web.xml中注册过滤器。配置它的属性

使用系统提供的字符集过滤器类过滤器的注册package com.example.config;import org.springframework.boot.web.servlet.FilterRegistrationBean;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import org.springframework.web.filter.CharacterEncodingFilter;@Configurationpublic class FilterConfig &#123;    @Bean    public FilterRegistrationBean filterRegistration() &#123;        FilterRegistrationBean bean = new FilterRegistrationBean();        //使用框架中的过滤器类        CharacterEncodingFilter filter = new CharacterEncodingFilter();        //指定使用的编码方式        filter.setEncoding(&quot;utf-8&quot;);        //指定request，response都使用encoding的值        filter.setForceEncoding(true);        bean.setFilter(filter);        //指定过滤的url地址        bean.addUrlPatterns(&quot;/*&quot;);        return bean;    &#125;&#125;
同时需要关闭SpringBoot中默认配置的字符集过滤器，使自定义的过滤器起作用。#SpringBoot中默认已经配置了Character Encoding Filter，默认编码ISO-8859-1#设置enable=false 作用是关闭系统中配置好的过滤器，使用自定义的CharacterEncodingFilterserver.servlet.encoding.enabled=false
直接修改application.properties配置#让系统的CharacterEncodingFilter生效server.servlet.encoding.enabled=true#指定使用的编码方式server.servlet.encoding.charset=UTF-8#强制request、response都使用charset属性的值server.servlet.encoding.force=true

